INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('real-estate-moex-00954', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '依民法之規定，稱典權者，謂支付典價在他人之不動產為使用、收益，於他人不回贖時，取得該不 動產所有權之權。下列關於典權之敘述，何者錯誤？ 典權人對於典物因轉典所受之損害，負賠償責任 典權之約定期限超過15年時，當事人間得附有到期不贖即作絕賣之條款 典權人為典物支出有益費用，使典物增加價值，不論該增益之價值是否仍然存在，得請求出典人 償還 未定期限之典權，出典人得隨時以原典價回贖典物。但自出典後經過30年不回贖者，典權人即取 得典物所有權', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00955', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '19歲之甲經父母同意受僱於乙公司。某日甲受乙公司之吩咐，將貨物送到客戶手中。途中行經十字 路口，甲闖紅燈致丙在綠燈穿越時受傷，經該地區行車事故鑑定委員會認定，認定甲應負全部之肇 事責任。就此情形，下列敘述何者錯誤？ 甲是未成年人，對於丙之損害，無須負賠償責任 丙得主張乙與甲負連帶損害賠償責任 丙得主張甲及其父母負連帶損害賠償責任 乙賠償丙之損害後，得向甲求償', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 30, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00956', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '就賣方甲與買方乙間訂立之買賣契約，下列敘述何者錯誤？ 該買賣標的物因可歸責於甲之事由而滅失，致給付不能者，乙得解除契約並請求損害賠償 該買賣標的物因不可歸責甲乙之事由而滅失，致給付不能者，甲得免除該物之給付義務 該買賣標的物因不可歸責甲乙之事由而滅失，致給付不能者，乙得免除價金支付之義務 該買賣標的物因可歸責乙之事由而滅失，致給付不能者，甲不得向乙請求價金之支付', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 31, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00957', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關夫妻離婚後所生身分及財產上效力之說明，何者正確？ 夫妻離婚後，其子女對未享有親權之父母一方，喪失原本享有之法定繼承權 夫妻離婚後，未享有親權之父母一方與其子女間，互相不負扶養之義務 兩願離婚之場合，關於子女之親權，由夫任之 夫妻無過失之一方，因判決離婚而限於生活困難者，他方縱無過失，亦應給予贍養費', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 32, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00958', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關遺產分割之敘述，何者錯誤？ 繼承人請求分割遺產之不動產，性質上為處分行為，依民法第759條規定，於未辦妥繼承登記前， 不得為之 被繼承人之遺囑，定有分割遺產之方法，或託他人代定者，從其所定 繼承人對被繼承人已屆清償期之債務，自遺產分割時起，15年內仍負連帶責任 繼承人之一所分得之土地持分短少，得向其他繼承人請求賠償短少分配之同額價金', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 33, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00959', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關繼承之敘述，何者錯誤？ 奠儀於繼承發生時並不存在，非屬被繼承人所遺財產 繼承人對於被繼承人之債務，以因繼承所得遺產為限，負清償責任 債權人得單獨向法院聲請命繼承人於3個月內提出遺產清冊 繼承人對於遺產全部為公同共有關係，無應有部分，故若逾越應繼分比例享有（行使）權利，毋 須負返還義務', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 34, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00960', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關意思表示之敘述，何者錯誤？ 因錯誤或被詐欺而締結契約者，在表意人依法撤銷其意思表示之前，契約效力未定 當事人之意思表示未合致者，其契約自始未成立 買賣為諾成契約，除當事人另有約定外，縱然未訂立書面，亦不影響契約之成立 非定期行為之契約，當事人一方遲延給付者，他方當事人得定相當期限催告其履行，如債務人仍 不履行時，債權人仍須另為解約之意思表示', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 35, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00961', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關租賃契約之敘述，何者錯誤？ 租賃關係存續中，出租人未使租賃物合於約定使用收益狀態，致承租人未達租賃目的者，承租人 得拒絕給付租金 出租人將已交付承租人之租賃物的所有權讓與他人，承租人與受讓人間仍須另立租賃契約始發生 租賃關係 定有期限之租賃契約，當事人約定得提前終止者，於終止契約前應先期通知 租賃契約經公證並附有逕受強制執行條款者，當承租人有不付租金、租期屆滿拒不搬遷，或房東 不返還押租金時，當事人可直接申請強制執行', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 36, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00962', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關抵押權之敘述，何者正確？ 以抵押權擔保之債權請求權，雖經時效消滅，債權人仍得於時效完成後5年內實行抵押權 以建築物為抵押者，其附加部分亦為抵押權效力所及，應一律併付拍賣 抵押權人聲請查封抵押物，惟該執行名義嗣後經抗告法院裁定予以廢棄確定時，抵押人可依法請 求財產上及非財產上損害賠償 抵押權人於債權清償期屆滿後，為受清償，不得訂立契約取得抵押物之所有權', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00963', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關契約解除之敘述，何者錯誤？ 契約解除時，當事人雙方負回復原狀之義務 解除權之行使，不妨礙損害賠償之請求 房屋買賣契約解除時，原買受人已支出之裝潢費用均得請求出賣人返還 解除權之行使，得以送達訴狀繕本予他方當事人之方法為之', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 38, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
